        $report.ok[1].name | Should -Be 'a'
    }

    It 'returns empty arrays for groups with no members' {
        $allOk = @(
            [pscustomobject]@{ name = 'x'; lastRotated = '2026-04-01'; rotationPolicyDays = 90; requiredBy = @() }
        )
